import Plot from 'react-plotly.js';
import { db } from '../firebase/config';
import { collection, getDocs } from 'firebase/firestore';

const CategoryValueChart = () => {
  const [chartData, setChartData] = useState({
    labels: [],
    values: [],
  });
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchProductValueData = async () => {
      try {
        const productsCollection = collection(db, 'products');
        const querySnapshot = await getDocs(productsCollection);

        const categoryValues = {}; // Use an object to sum values by category

        querySnapshot.forEach((doc) => {
          const product = doc.data();
          if (product.category && product.price && product.quantity) {
            const value = product.price * product.quantity;
            if (categoryValues[product.category]) {
              categoryValues[product.category] += value;
            } else {
              categoryValues[product.category] = value;
            }
          }
        });

        // Convert the aggregated object into arrays for Plotly
        const labels = Object.keys(categoryValues);
        const values = Object.values(categoryValues).map(val => val.toFixed(2)); // Format to 2 decimal places

        setChartData({ labels, values });
      } catch (error) {
        console.error("Error fetching product data for value chart:", error);
      } finally {
        setIsLoading(false);
      }
    };

    fetchProductValueData();
  }, []);

  if (isLoading) {
    return <div className="text-center text-gray-400">Loading Chart...</div>;
  }

  // Use a dark theme for the plot
  const layout = {
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    title: {
      text: 'Total Stock Value (€)',
      font: { color: '#E5E7EB' } // Gray-200
    },
    xaxis: {
      title: 'Product Category',
      tickfont: { color: '#D1D5DB' }, // Gray-300
      titlefont: { color: '#9CA3AF' } // Gray-400
    },
    yaxis: {
      title: 'Total Value (€)',
      tickfont: { color: '#D1D5DB' },
      titlefont: { color: '#9CA3AF' }
    },
    height: 400,
    margin: { t: 50, b: 100, l: 60, r: 40 },
  };

  return (
    <div>
      <h2 className="text-xl font-semibold mb-4 text-gray-200 text-center">Inventory Value by Category</h2>
      <Plot
        data={[
          {
            x: chartData.labels,
            y: chartData.values,
            type: 'bar',
            marker: {
              color: '#D97706', // Amber-600, similar to mictlan-gold
            },
            hovertemplate: '<b>%{x}</b><br>Value: %{y}€<extra></extra>',
          },
        ]}
        layout={layout}
        config={{ responsive: true }}
        className="w-full"
      />
    </div>
  );
};

export default CategoryValueChart;
"}

